file.content:
.contractor-portal-page {
  position: relative;
  min-height: 100vh;
  padding: 22px 0 44px;
  background-color: #ffffff;
  background-image: linear-gradient(
    to bottom,
    rgba(206, 220, 235, 0.55) 0%,
    rgba(206, 220, 235, 0.3) 12%,
    rgba(206, 220, 235, 0) 30%
  );
  overflow: hidden;

  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 15%;
    background-image: repeating-linear-gradient(
      -17deg,
      rgba(206, 220, 235, 0.18) 0,
      rgba(140, 149, 160, 0.18) 0.3px,
      transparent 1px,
      transparent 18px
    );
    pointer-events: none;
    z-index: 0;
  }

  .contractor-portal-card {
    position: relative;
    z-index: 1;
    width: 760px;
    margin: 0 auto;
    padding: 16px 22px 28px;
    // background: #ffffff;
    // border: 1px solid #edf1f6;
    border-radius: 6px;
    color: #1d2129;

    .permit-code {
      margin-bottom: 10px;
      font-size: 10px;
      display: inline-block;
      width: 153;
      height: 24;
      padding: 2px 12px;
      gap: 10px;
      border-radius: 8px;
      background-color: #e8fbff;
      color: #30647f;
    }

    .main-title {
      margin-top: 20px;
      font-weight: 500;
      font-size: 32px;
      line-height: 100%;
      text-transform: uppercase;
      color: #1d2129;
    }

    .subtitle {
      font-weight: 400;
      font-size: 14px;
      line-height: 22px;
      color: #4e5969;
      margin-top: 8px;
      margin-bottom: 48px;
    }

    section {
      margin-bottom: 48px;
      .section-title {
        font-family: Helvetica Neue;
        font-weight: 700;
        font-style: Bold;
        font-size: 16px;
        line-height: 24px;
        letter-spacing: 0%;
        vertical-align: middle;
        text-transform: uppercase;
        color: #30647f;
        margin-bottom: 20px;
      }
    }

    .permit-details-box {
      padding: 14px;
      background: #f2f4f5;
      border-radius: 12px;

      .detail-grid {
        .label {
          font-weight: 400;
          font-size: 14px;
          line-height: 22px;
          letter-spacing: 0%;
          color: #86909c;
        }

        .value {
          font-weight: 400;
          font-size: 14px;
          line-height: 22px;
          letter-spacing: 0%;
          color: #1d2129;
        }
      }
    }

    .form-row {
      position: relative;
      margin-bottom: 12px;
      &.arco-form-item {
        margin-bottom: 12px;
      }

      .arco-form-item-label-col {
        > label {
          display: block;
          margin-bottom: 5px;
          font-size: 11px;
          color: #4e5969;
        }
      }

      .arco-input-wrapper,
      .arco-input {
        height: 30px;
        font-size: 11px;
      }

      .arco-input {
        background: #f7f8fa;
        border: 1px solid #edf1f6;
      }

      .arco-textarea {
        background: #f7f8fa;
      }

      .word-count {
        position: absolute;
        right: 8px;
        bottom: 7px;
        font-size: 10px;
        color: #c2c7d0;
      }

      .arco-form-item-message {
        min-height: 14px;
        margin-top: 2px;
        font-size: 10px;
        line-height: 14px;
      }
    }

    .docs-list {
      .doc-row {
        display: flex;
        justify-content: space-between;
        align-items: flex-start;
        padding: 12px 0;
        border-bottom: 1px solid #f2f3f5;
        .doc-content {
          flex: 1;
          min-width: 0;
          .doc-title {
            margin-bottom: 2px;
            color: #1d2129;
            font-weight: 500;
            font-size: 14px;
            line-height: 22px;
          }

          .doc-desc {
            margin-bottom: 6px;
            font-weight: 400;
            font-size: 14px;
            line-height: 22px;
            letter-spacing: 0%;
            color: #86909c;
          }

          .file-tags {
            display: flex;
            flex-wrap: wrap;
            gap: 6px;

            .file-tag {
              display: inline-flex;
              align-items: center;
              gap: 4px;
              max-width: 220px;
              padding: 0px 8px;
              border-radius: 4px;
              background: #f3f3f3;
              color: #4e5969;
              font-size: 10px;
              line-height: 14px;
              height: 30px;

              .file-tag-icon {
                font-size: 10px;
                color: #7b8aa1;
              }

              .file-tag-close {
                margin-left: 2px;
                color: #b4beca;
              }
            }

            .file-tag-error {
              border-color: #f3d2d2;
              background: #fff7f7;
              color: #c94f4f;

              .file-tag-icon,
              .file-tag-close {
                color: #c94f4f;
              }
            }
          }
        }

        .attach-btn {
          width: 120px;
          height: 32px;
          gap: 8px;
          border-radius: 8px;
          border: 1px solid #30647f;
        }
      }
    }

    .more-info-list {
      .form-row:last-child,
      .arco-form-item:last-child {
        margin-bottom: 0;
      }
    }

    .pledge-form-row {
      margin-bottom: 8px;

      .arco-form-item-message {
        margin-top: 4px;
        font-size: 10px;
      }
    }

    .pledge-list {
      // display: flex;
      // flex-direction: column;
      // gap: 8px;
      // margin-bottom: 10px;

      .arco-checkbox {
        font-size: 10px;
        color: #4e5969;
        font-weight: 400;
        font-size: 14px;
        line-height: 22px;
        color: #1d2129;
        display: flex;
        align-items: center;
        margin-top: 10px;
      }
      .acceptance {
        font-weight: 400;
        font-size: 14px;
        line-height: 22px;
        color: #4e5969;
        margin-top: -10;
        body[dir='ltr'] & {
          padding-left: 26px;
        }
        body[dir='rtl'] & {
          padding-right: 26px;
        }
      }

      .arco-checkbox-checked {
        .arco-checkbox-icon {
          background-color: #3b729f;
          border-color: #3b729f;
        }
      }
    }

    .authorization-title {
      margin-bottom: 4px;
      font-size: 11px;
      color: #1d2129;
    }

    .authorization-desc {
      margin: 0;
      font-size: 10px;
      line-height: 16px;
      color: #4e5969;
    }

    .signature-area {
      margin: 0;

      .left-form {
        .form-row:last-child,
        .arco-form-item:last-child {
          margin-bottom: 0;
        }
      }
      .signature-form {
        display: flex;
        justify-content: space-between;
        .signature-iconRefresh {
          // border: 1px solid red;
          display: flex;
          gap: 4px;
          font-weight: 400;
          font-size: 14px;
          line-height: 22px;
          color: #86909c;
          cursor: pointer;
        }
      }
      .signature-card {
        padding: 10px;
        border: 1px solid #f2f3f5;
        border-radius: 8px;
        background: #fafbfc;

        .signature-placeholder {
          display: flex;
          align-items: center;
          justify-content: center;
          height: 74px;
          border-radius: 2px;
          background: #ffffff;
          border: 1px solid #edf1f6;
          font-size: 46px;
          line-height: 1;
          color: #2b2f35;
          font-family: cursive;
        }
      }
    }

    .action-group {
      display: flex;
      justify-content: center;
      gap: 14px;
      margin-top: 2px;
      justify-content: end;
      .save-btn,
      .submit-btn {
        width: 160px;
      }
    }
  }
}

.submit-confirm-modal {
  .arco-modal {
    width: 420px;
    border-radius: 10px;
    overflow: hidden;
  }

  .arco-modal-content {
    padding: 16px 18px 14px;
    border-radius: 10px;
  }

  .arco-modal-close-icon {
    color: #5e6878;
    font-size: 14px;
    top: 12px;
    right: 12px;
  }

  .submit-confirm-content {
    margin-top: 10px;
    .submit-confirm-header {
      display: flex;
      align-items: center;
      gap: 10px;
      margin-bottom: 8px;
      .submit-confirm-icon {
        display: flex;
        align-items: center;
        justify-content: center;
        width: 16px;
        height: 16px;
        border-radius: 50%;
        background: #f58f54;
        color: #ffffff;
        font-size: 12px;
        line-height: 1;
        font-weight: 700;
        font-family: 'Times New Roman', serif;
      }

      .submit-confirm-title {
        font-weight: 500;
        font-size: 16px;
        line-height: 100%;
        color: #1d2129;
      }
    }

    .submit-confirm-desc {
      display: flex;
      body[dir='ltr'] & {
        margin-left: 26px;
      }
      body[dir='rtl'] & {
        margin-right: 26px;
      }

      margin-bottom: 12px;
      font-size: 12px;
      font-weight: 400;
      font-size: 14px;
      line-height: 100%;
      color: #4e5969;
    }

    .submit-confirm-actions {
      display: flex;
      justify-content: end;
      gap: 8px;
    }
  }
}

