.contractor-portal-detail {
  min-height: 100vh;
  background: #fff;
  background-image: linear-gradient(
    to bottom,
    rgba(206, 220, 235, 0.65) 0%,
    rgba(206, 220, 235, 0.35) 13%,
    rgba(206, 220, 235, 0) 34%
  );
  padding: 24px 0 40px;
  position: relative;

  &::before {
    content: '';
    position: absolute;
    inset: 0 0 auto 0;
    height: 170px;
    background-image: repeating-linear-gradient(
      -17deg,
      rgba(157, 180, 201, 0.22) 0,
      rgba(157, 180, 201, 0.22) 0.5px,
      transparent 1px,
      transparent 20px
    );
    pointer-events: none;
    z-index: 0;
  }

  &__card {
    width: 920px;
    margin: 0 auto;
    position: relative;
    z-index: 1;
    padding: 14px 26px 0px;
    // background: #fff;
    color: #1d2129;
  }

  &__expired {
    min-height: 220px;
    display: flex;
    flex-direction: column;
    justify-content: center;
    border-radius: 12px;
    background: rgba(255, 255, 255, 0.92);
    border: 1px solid #edf1f4;
  }

  &__permit-code {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    height: 24px;
    background: #e8fbff;
    color: #30647f;
    font-size: 10px;
    line-height: 24px;
    padding: 0 12px;
    border-radius: 8px;
    box-sizing: border-box;
  }

  &__title {
    margin: 18px 0 8px;
    font-size: 42px;
    line-height: 1;
    font-weight: 700;
    letter-spacing: 0.2px;
    text-transform: uppercase;
  }

  &__subtitle {
    margin: 0 0 28px;
    color: #4e5969;
    font-size: 14px;
    line-height: 22px;
  }

  &__section {
    margin-bottom: 28px;
    border-bottom: 1px solid #edf1f4;
    padding-bottom: 20px;

    &--signature {
      margin-bottom: 18px;
      padding-bottom: 16px;
    }

    &-title {
      margin: 0 0 14px;
      color: #30647f;
      font-size: 24px;
      line-height: 1.2;
      font-weight: 700;
      text-transform: uppercase;
    }
  }

  &__panel {
    border-radius: 12px;
    background: #f2f4f5;
    padding: 14px 16px;
  }

  &__label {
    color: #86909c;
    font-size: 14px;
    line-height: 22px;
    margin-bottom: 2px;
  }

  &__value {
    color: #1d2129;
    font-size: 14px;
    line-height: 22px;
    word-break: break-word;
  }

  &__field-block {
    margin-bottom: 10px;
  }

  &__file {
    &-row {
      margin-top: 10px;
    }

    &-wrap {
      display: flex;
      gap: 10px;
      flex-wrap: wrap;
    }

    &-tag {
      height: 30px;
      min-width: 150px;
      display: inline-flex;
      align-items: center;
      gap: 6px;
      font-size: 12px;
      color: #4e5969;
      border-radius: 4px;
      background: #f6f7f8;
      padding: 0 10px;

      svg {
        color: #7b8aa1;
        font-size: 12px;
      }
    }
  }

  &__check {
    width: 16px;
    height: 16px;
    border-radius: 2px;
    background: #3b729f;
    color: #fff;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    margin-top: 3px;
    flex-shrink: 0;

    svg {
      font-size: 10px;
    }
  }

  &__pledge {
    &-item {
      display: flex;
      align-items: flex-start;
      gap: 8px;
      margin-bottom: 8px;
      color: #1d2129;
      font-size: 14px;
      line-height: 22px;
    }

    &-acceptance {
      color: #4e5969;
      font-size: 14px;
      line-height: 22px;
      margin-left: 24px;
      max-width: 860px;
    }
  }

  &__signature {
    &s {
      display: grid;
      grid-template-columns: repeat(3, minmax(0, 1fr));
      gap: 12px;
    }

    &-card {
      border-radius: 6px;
      border: 1px solid #edf1f4;
      background: #f9fbfc;
      padding: 8px 10px 12px;
    }

    &-dot {
      width: 6px;
      height: 6px;
      border-radius: 50%;
      background: #3b729f;
      margin-bottom: 4px;
    }

    &-role {
      font-weight: 500;
      font-size: 16px;
      line-height: 22px;
      color: #30647f;
    }

    &-time {
      font-size: 11px;
      line-height: 18px;
      color: #86909c;
      margin-bottom: 8px;
    }

    &-meta {
      display: flex;
      flex-direction: column;
      gap: 1px;
      margin-bottom: 8px;

      span {
        color: #86909c;
        font-size: 11px;
        line-height: 18px;
      }

      strong {
        color: #1d2129;
        font-size: 12px;
        line-height: 20px;
        font-weight: 500;
      }
    }

    &-text {
      font-family: 'Brush Script MT', 'Lucida Handwriting', cursive;
      color: #2e3442;
      font-size: 36px;
      line-height: 1;
    }
  }

  .exportPDF-box {
    position: fixed;
    top: 0;
    left: -100000px;
    z-index: -1;
    pointer-events: none;
  }
}

.token-expired {
  display: flex;
  align-items: center;
  justify-content: center;
}

.footer-box {
  display: flex;
  justify-content: center;
  padding-bottom: 50px;
  .footer {
    display: flex;
    justify-content: flex-end;
    margin-top: 8px;
    width: 980px;
    .arco-btn {
      min-width: 100px;
      border-radius: 8px;
      background: linear-gradient(to bottom, #4a8099, #30647f);
      border: none;
    }
  }
}

