    font-size: 14px;
    line-height: 22px;
    word-break: break-word;
  }

  &__field-block {
    margin-bottom: 10px;
  }

  &__file {
    &-row {
      margin-top: 10px;
    }

    &-wrap {
      display: flex;
      gap: 10px;
      flex-wrap: wrap;
    }

    &-tag {
      height: 30px;
      min-width: 150px;
      display: inline-flex;
      align-items: center;
      gap: 6px;
      font-size: 12px;
      color: #4e5969;
      border-radius: 4px;
      background: #f6f7f8;
      padding: 0 10px;

      svg {
        color: #7b8aa1;
        font-size: 12px;
      }
    }
  }

  &__check {
    width: 16px;
    height: 16px;
    border-radius: 2px;
    background: #3b729f;
    color: #fff;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    margin-top: 3px;
    flex-shrink: 0;

    svg {
      font-size: 10px;
    }
  }

  &__pledge {
    &-item {
      display: flex;
      align-items: flex-start;
      gap: 8px;
      margin-bottom: 8px;
      color: #1d2129;
      font-size: 14px;
      line-height: 22px;
    }

    &-acceptance {
      color: #4e5969;
      font-size: 14px;
      line-height: 22px;
      margin-left: 24px;
      max-width: 860px;
    }
  }

  &__signature {
    &s {
      display: grid;
      grid-template-columns: repeat(3, minmax(0, 1fr));
      gap: 12px;
    }

    &-card {
      border-radius: 6px;
      border: 1px solid #edf1f4;
      background: #f9fbfc;
      padding: 8px 10px 12px;
    }

    &-dot {
      width: 6px;
      height: 6px;
      border-radius: 50%;
      background: #3b729f;
      margin-bottom: 4px;
    }

    &-role {
      font-weight: 500;
      font-size: 16px;
      line-height: 22px;
      color: #30647f;
    }

    &-time {
      font-size: 11px;
      line-height: 18px;
      color: #86909c;
      margin-bottom: 8px;
    }

    &-meta {
      display: flex;
      flex-direction: column;
      gap: 1px;
      margin-bottom: 8px;

      span {
        color: #86909c;
        font-size: 11px;
        line-height: 18px;
      }

      strong {
        color: #1d2129;
        font-size: 12px;
        line-height: 20px;
        font-weight: 500;
      }
    }

    &-text {
      font-family: 'Brush Script MT', 'Lucida Handwriting', cursive;
      color: #2e3442;
      font-size: 36px;
      line-height: 1;
    }
  }

  .exportPDF-box {
    position: fixed;
    top: 0;
    left: -100000px;
    z-index: -1;
    pointer-events: none;
  }
}

.token-expired {
  display: flex;
  align-items: center;
  justify-content: center;
}

.footer-box {
  display: flex;
  justify-content: center;
  padding-bottom: 50px;
  .footer {
    display: flex;
    justify-content: flex-end;
    margin-top: 8px;
    width: 980px;
    .arco-btn {
      min-width: 100px;
      border-radius: 8px;
      background: linear-gradient(to bottom, #4a8099, #30647f);
      border: none;
    }
  }
}

