      color: #86909c;
      margin-bottom: 10px;
      line-height: 22px;
    }

    &-trigger {
      width: 64px;
      height: 64px;
      border: 1px dashed #e5e6eb;
      border-radius: 4px;
      background-color: #fff;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      color: #86909c;
      font-size: 12px;
      cursor: pointer;
      gap: 4px;
      transition:
        border-color 0.2s,
        color 0.2s;

      .arco-icon {
        font-size: 20px;
      }

      &:hover {
        border-color: #30647f;
        color: #30647f;
      }
    }
  }

  .arco-upload-trigger-picture {
    width: auto;
    height: auto;
    border: none;
    background-color: transparent;
    padding: 0;
  }

  // ── Submit confirmation modal ─────────────────────────────────────────────
  &__confirm-modal {
    display: flex;
    flex-direction: column;
    gap: 24px;
  }

  &__confirm-modal-header {
    display: flex;
    align-items: flex-start;
    gap: 16px;
  }

  &__confirm-modal-icon {
    font-size: 24px;
    color: #ff7d00;
    flex-shrink: 0;
    margin-top: 1px;
  }

  &__confirm-modal-title {
    font-size: 16px;
    font-weight: 500;
    color: #1d2129;
    margin-bottom: 8px;
  }

  &__confirm-modal-desc {
    font-size: 14px;
    color: #4e5969;
    line-height: 1.5;
  }

  &__confirm-modal-field {
    padding-left: 40px;
  }

  &__confirm-modal-label {
    font-size: 14px;
    color: #4e5969;
    margin-bottom: 8px;
    line-height: 22px;
  }

  &__confirm-modal-footer {
    display: flex;
    justify-content: flex-end;
    gap: 10px;

    .arco-btn-primary {
      background: linear-gradient(to top, #30647f, #4a8099);
      border-color: transparent;

      &:hover {
        background: linear-gradient(to top, #265569, #3d7088);
      }
    }
  }

  // ── Footer ────────────────────────────────────────────────────────────────
  &__footer {
    position: sticky;
    bottom: 0;
    z-index: 10;
    flex-shrink: 0;
    display: flex;
    align-items: center;
    justify-content: flex-end;
    gap: 12px;
    padding: 16px 20px;
    background-color: #fff;
    border-top: 1px solid #e5e6eb;
  }
  .footer-back {
    border: 1px solid #e5e6eb;
    background-color: rgb(255, 255, 255);
    color: #30647f;
  }
}

