    flex-direction: column;
    padding: 16px 20px 20px;
  }

  // ── Main card ─────────────────────────────────────────────────────────────
  &__card {
    flex: 1;
    display: flex;
    flex-direction: column;
    background-color: #fff;
    border: 1px solid #f2f3f5;
    border-radius: 12px;
    box-shadow: 0 4px 8px 0 rgba(0, 0, 0, 0.05);
    overflow: clip;
  }

  // ── Card header ───────────────────────────────────────────────────────────
  &__card-header {
    flex-shrink: 0;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 20px;
    height: 56px;
    border-bottom: 1px solid #e5e6eb;
  }

  &__card-title {
    font-size: 16px;
    font-weight: 500;
    color: #1d2129;
    text-transform: uppercase;
    letter-spacing: 0.5px;
  }

  // ── Status badge ──────────────────────────────────────────────────────────
  &__status-badge {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    height: 28px;
    padding: 0 12px;
    border-radius: 6px;
    border: 1px solid rgba(134, 144, 156, 0.4);
    background-color: rgba(134, 144, 156, 0.05);

    &-dot {
      width: 8px;
      height: 8px;
      border-radius: 50%;
      background-color: #86909c;
      flex-shrink: 0;
    }

    &-text {
      font-size: 14px;
      color: #86909c;
    }
  }

  // ── Meta bar ──────────────────────────────────────────────────────────────
  &__meta-bar {
    flex-shrink: 0;
    display: flex;
    align-items: center;
    gap: 36px;
    padding: 12px 20px;
    background-color: #f7f8fa;
    border-bottom: 1px solid #e5e6eb;
  }

  &__meta-item {
    display: flex;
    align-items: center;
    gap: 8px;
  }

  &__meta-label {
    font-size: 13px;
    color: #86909c;
    white-space: nowrap;
  }

  &__meta-value {
    font-size: 14px;
    font-weight: 500;
    color: #1d2129;
    white-space: nowrap;
  }

  // ── Main two-column area ──────────────────────────────────────────────────
  &__main {
    flex: 1;
    display: flex;
    overflow: hidden;
  }

  // ── Sidebar ───────────────────────────────────────────────────────────────
  &__sidebar {
    width: 230px;
    flex-shrink: 0;
    border-right: 1px solid #e5e6eb;
    overflow-y: auto;
    padding: 12px 0 20px;
    background-color: #fff;
  }

  // Top-level clickable nav item (Around the Building)
  &__nav-item {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 9px 16px;
    font-size: 14px;
    font-weight: 500;
    color: #4e5969;
    cursor: pointer;
    position: relative;
    user-select: none;
    transition: background-color 0.15s, color 0.15s;

    &:hover:not(&--active) {
      background-color: #f7f8fa;
      color: #1d2129;
    }

    &--active {
      color: #30647f;
      background-color: #f0f7fb;

      &::before {
        content: '';
        position: absolute;
        left: 0;
        top: 0;
        bottom: 0;
        width: 3px;
        background-color: #30647f;
        border-radius: 0 2px 2px 0;
      }
    }
  }

  // Clickable group header (Inside the Building, Parking)
  &__nav-group-header {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 9px 16px;
    font-size: 14px;
    font-weight: 500;
    color: #4e5969;
    margin-top: 4px;
    cursor: pointer;
    user-select: none;
    transition: background-color 0.15s, color 0.15s;

    &:hover:not(&--active) {
      background-color: #f7f8fa;
      color: #1d2129;
    }

    &--active {
      color: #30647f;
    }
  }

  // Child nav item (floors, P1/P2/P3)
  &__nav-child {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 7px 16px 7px 32px;
    font-size: 13px;
    font-weight: 400;
    color: #4e5969;
    cursor: pointer;
    position: relative;
    user-select: none;
    transition: background-color 0.15s, color 0.15s;

    &:hover:not(&--active) {
      background-color: #f7f8fa;
      color: #1d2129;
    }

    &--active {
      color: #30647f;
      background-color: #f0f7fb;
      font-weight: 500;

      &::before {
        content: '';
        position: absolute;
        left: 0;
        top: 0;
        bottom: 0;
        width: 3px;
        background-color: #30647f;
      }
    }
  }

  &__nav-label {
    flex: 1;
    min-width: 0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  // Filled dot for parent-level items
  &__nav-dot {
    width: 8px;
    height: 8px;
    border-radius: 50%;
    background-color: #c9cdd4;
    flex-shrink: 0;

    &--active {
      background-color: #30647f;
    }
  }

  // Hollow dot for child items
  &__nav-child-dot {
    width: 6px;
    height: 6px;
    border-radius: 50%;
    border: 1.5px solid #c9cdd4;
    background: transparent;
    flex-shrink: 0;

    &--active {
      border-color: #30647f;
      background-color: #30647f;
    }
  }

  // Number badge in sidebar (findings count)
  &__nav-badge {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: 20px;
    height: 18px;
    padding: 0 6px;
    border-radius: 4px;
    background-color: #ffeae8;
    color: #f5626c;
    font-size: 11px;
    font-weight: 500;
    line-height: 1;
    flex-shrink: 0;
  }

  // Green checkmark circle (shared: sidebar + other badges)
  &__badge-ok {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 16px;
    height: 16px;
    border-radius: 50%;
    background-color: #00b42a;
    color: #fff;
    font-size: 10px;
    font-weight: 700;
    line-height: 1;
    flex-shrink: 0;
  }

  // ── Content area (right side) ─────────────────────────────────────────────
  &__content-area {
    flex: 1;
    overflow-y: auto;
    padding: 28px 36px;

    .arco-form {
      height: 100%;
    }
  }

  // Content header: title + subtitle + Check & Save button
  &__content-header {
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    margin-bottom: 24px;
    gap: 16px;
  }

  &__content-title {
    font-size: 28px;
    font-weight: 500;
    color: #1d2129;
    line-height: 1.3;
    margin-bottom: 6px;
  }

  &__content-subtitle {
    font-size: 13px;
    color: #86909c;
    line-height: 1.5;
  }

  &__check-save-btn {
    flex-shrink: 0;
    background: linear-gradient(to top, #30647f, #4a8099) !important;
    border-color: transparent !important;

    &:hover {
      background: linear-gradient(to top, #265569, #3d7088) !important;
    }
  }

  // ── Section cards ─────────────────────────────────────────────────────────
  &__sections {
    display: flex;
    flex-direction: column;
    gap: 20px;
  }

  &__loading {
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 80px 0;
  }

  &__section {
    border: 1px solid #e5e6eb;
    border-radius: 8px;
    overflow: hidden;

    &-header {
      display: flex;
      align-items: center;
      justify-content: space-between;
      min-height: 72px;
      padding: 12px 20px;
      background-color: #f7f8fa;
      cursor: pointer;
      user-select: none;
      transition: background-color 0.15s;

      &--open {
        border-bottom: 1px solid #e5e6eb;
      }

      &:hover {
        background-color: #f0f1f2;
      }

      .arco-icon {
        font-size: 16px;
        color: #1d2129;
        flex-shrink: 0;
      }
    }

    &-no {
      font-size: 12px;
      font-weight: 500;
      color: #30647f;
      text-transform: uppercase;
      letter-spacing: 0.3px;
      line-height: 22px;
      margin-bottom: 2px;
    }

    &-title {
      font-size: 20px;
      font-weight: 500;
      color: #1d2129;
      text-transform: uppercase;
      letter-spacing: 1px;
      line-height: 1.2;
    }

    &-body {
      padding: 0 20px;
    }
  }

  // ── Question items ────────────────────────────────────────────────────────
  &__item {
    padding: 24px 0;
    border-bottom: 1px solid #e5e6eb;

    &:last-child {
      border-bottom: none;
    }

    &-question {
      font-size: 18px;
      font-weight: 500;
      color: #1d2129;
      margin-bottom: 12px;
      line-height: 1.4;
    }

    .arco-form-item {
      margin-bottom: 0;
    }
  }

  // ── Yes/No toggle ─────────────────────────────────────────────────────────
  &__yes-no {
    display: inline-flex;
    align-items: center;
    width: 240px;
    height: 36px;
    padding: 4px;
    gap: 4px;
    border-radius: 8px;
    background-color: #f7f8fa;
    overflow: hidden;

    &-btn {
      flex: 1;
      height: 100%;
      border: none;
      background: transparent;
      color: #86909c;
      font-size: 14px;
      border-radius: 4px;
      cursor: pointer;
      transition: background-color 0.15s, color 0.15s;

      &--yes-active {
        background: linear-gradient(to top, #30647f, #4a8099);
        color: #fff;
      }

      &--no-active {
        background: linear-gradient(to top, #cb3d4b, #f5626c);
        color: #fff;
      }
    }
  }

  // ── Findings wrap ─────────────────────────────────────────────────────────
  &__findings-wrap {
    margin-top: 20px;
    background-color: #f7f8fa;
    border-radius: 8px;
    padding: 12px;
    display: flex;
    flex-direction: column;
    gap: 20px;
  }

  &__findings-list {
    display: flex;
    flex-direction: column;
    gap: 16px;
  }

  &__finding-divider {
    height: 1px;
    background-color: #e5e6eb;
    flex-shrink: 0;
  }

  &__add-finding-btn {
    color: #30647f !important;
    border-color: #e5e6eb !important;
    background-color: #fff !important;
    align-self: flex-start;

    &:hover {
      color: #1a6f8a !important;
      border-color: #30647f !important;
    }
  }

  // ── Individual finding card ───────────────────────────────────────────────
  &__finding {
    &-head {
      display: flex;
      align-items: center;
      justify-content: space-between;
      margin-bottom: 20px;
    }

    &-title {
      font-size: 16px;
      font-weight: 500;
      color: #1d2129;
      text-transform: uppercase;
    }

    &-body {
      display: flex;
      flex-direction: column;
      gap: 20px;

      .arco-textarea,
      .arco-input-wrapper,
      .arco-select-view,
      .arco-picker {
        background-color: #ffffff;
      }

      .arco-textarea:focus,
      .arco-input-wrapper:focus-within,
      .arco-select-view:focus-within,
      .arco-picker:focus-within {
        background-color: #ffffff;
      }
    }

    &-row {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 12px;

      .arco-form-item {
        margin-bottom: 0;
      }

      .arco-form-label-item {
        margin-bottom: 6px;
      }
    }
  }

  // ── Field blocks ──────────────────────────────────────────────────────────
  &__field {
    &-block {
      .arco-form-item {
        margin-bottom: 0;
      }
    }

    &-label {
      font-size: 14px;
      color: #4e5969;
      margin-bottom: 8px;
      line-height: 22px;

      &--required::before {
        content: '* ';
        color: #f53f3f;
      }
    }
  }

  // ── Upload ────────────────────────────────────────────────────────────────
  &__upload {
    &-tip {
      font-size: 12px;
      color: #86909c;
      margin-bottom: 10px;
      line-height: 22px;
    }

    &-trigger {
      width: 64px;
      height: 64px;
      border: 1px dashed #e5e6eb;
      border-radius: 4px;
      background-color: #fff;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      color: #86909c;
      font-size: 12px;
      cursor: pointer;
      gap: 4px;
      transition: border-color 0.2s, color 0.2s;

      .arco-icon {
        font-size: 20px;
      }

      &:hover {
        border-color: #30647f;
        color: #30647f;
      }
    }
  }

  .arco-upload-trigger-picture {
    width: auto;
    height: auto;
    border: none;
    background-color: transparent;
    padding: 0;
  }

  // ── Submit confirmation modal ─────────────────────────────────────────────
  &__confirm-modal {
    display: flex;
    flex-direction: column;
    gap: 24px;
  }

  &__confirm-modal-header {
    display: flex;
    align-items: flex-start;
    gap: 16px;
  }

  &__confirm-modal-icon {
    font-size: 24px;
    color: #ff7d00;
    flex-shrink: 0;
    margin-top: 1px;
  }

  &__confirm-modal-title {
    font-size: 16px;
    font-weight: 500;
    color: #1d2129;
    margin-bottom: 8px;
  }

  &__confirm-modal-desc {
    font-size: 14px;
    color: #4e5969;
    line-height: 1.5;
  }

  &__confirm-modal-field {
    padding-left: 40px;
  }

  &__confirm-modal-label {
    font-size: 14px;
    color: #4e5969;
    margin-bottom: 8px;
    line-height: 22px;
  }

  &__confirm-modal-footer {
    display: flex;
    justify-content: flex-end;
    gap: 10px;

    .arco-btn-primary {
      background: linear-gradient(to top, #30647f, #4a8099);
      border-color: transparent;

      &:hover {
        background: linear-gradient(to top, #265569, #3d7088);
      }
    }
  }

  // ── Footer ────────────────────────────────────────────────────────────────
  &__footer {
    position: sticky;
    bottom: 0;
    z-index: 10;
    flex-shrink: 0;
    display: flex;
    align-items: center;
    justify-content: flex-end;
    gap: 12px;
    padding: 16px 20px;
    background-color: #fff;
    border-top: 1px solid #e5e6eb;

    .arco-btn-primary {
      background: linear-gradient(to top, #30647f, #4a8099);
      border-color: transparent;

      &:hover {
        background: linear-gradient(to top, #265569, #3d7088);
      }
    }
  }
}

