.ratrol-record-detail {
  display: flex;
  flex-direction: column;
  width: 100%;
  height: 100%;
  background-color: #f2f3f5;
  overflow: hidden;

  // ── Page wrapper ──────────────────────────────────────────────────────────
  &__wrapper {
    flex: 1;
    overflow: hidden;
    display: flex;
    flex-direction: column;
    padding: 16px 20px 20px;
  }

  // ── Main card ─────────────────────────────────────────────────────────────
  &__card {
    flex: 1;
