  }

  // ── Card header ───────────────────────────────────────────────────────────
  &__card-header {
    flex-shrink: 0;
    display: flex;
    align-items: center;
    justify-content: space-between;
    height: 56px;
    padding: 0 20px;
    border-bottom: 1px solid #e5e6eb;
  }

  &__card-title {
    font-size: 16px;
    font-weight: 500;
    color: #1d2129;
    text-transform: uppercase;
    letter-spacing: 0.5px;
  }

  // ── Status badge ─────────────────────────────────────────────────────────
  &__status-badge {
    display: inline-flex;
    align-items: center;
